INSERT INTO TB_ADMIN_SVR_LOG_INFO (
	  LOG_ID
    , CLASS_NM
    , METHOD_NM
    , REQ_URI
    , HTTP_METHOD
    , CLIENT_IP
    , REG_ID
    , REG_DT
) VALUES (
	 (SELECT FN_GET_UNIQUE_KEY())
   , #{classNm}
   , #{methodNm}
   , #{reqUri}
   , #{httpMethod}
   , #{clientIp}
   , #{regId}
   , NOW()
)
